import { forwardRef } from "react";
import type { HTMLAttributes, ReactNode } from "react";
import * as styles from "./_BaseIcon.css";
import type { IconInnerSize } from "./Icon.config";
import { clsx } from "clsx";

export interface BaseIconProps extends HTMLAttributes<HTMLSpanElement> {
  /**
   * The icon content (typically an SVG element)
   */
  children: ReactNode;

  /**
   * The size of the icon in pixels
   * @default 12
   */
  size?: IconInnerSize;
}

/**
 * @internal
 * Base icon component without container padding.
 * Use `Icon` for the public API with proper container sizing.
 */
export const _BaseIcon = forwardRef<HTMLSpanElement, BaseIconProps>(
  ({ children, size = 12, className, ...props }, ref) => {
    return (
      <span
        ref={ref}
        className={clsx(styles.baseIcon({ size }), className)}
        {...props}
      >
        {children}
      </span>
    );
  }
);

_BaseIcon.displayName = "_BaseIcon";
